$base = __DIR__;
$log  = [];

function write_file($path, $b64gz) {
    global $log;
    $content = gzdecode(base64_decode($b64gz));
    if ($content === false) { $log[] = "ERROR decodificando: $path"; return; }
    if (file_put_contents($path, $content) !== false)
        $log[] = "✓ " . basename($path);
    else
        $log[] = "✗ ERROR escribiendo: $path";
}

function copy_img($src_name, $dst_name, $base) {
    global $log;
    // Possible locations of glvservicesexp.com assets
    $home     = dirname(dirname(dirname($base)));
    $try_paths = [
        "$home/public_html/assets/images/$src_name",
        dirname($base) . "/assets/images/$src_name",
        "$home/assets/images/$src_name",
    ];
    foreach ($try_paths as $src) {
        if (file_exists($src)) {
            copy($src, "$base/imagenes/$dst_name");
            $log[] = "✓ img: $dst_name";
            return;
        }
    }
    $log[] = "⚠ img no encontrada: $src_name (colócala manualmente en imagenes/)";
}

// Create imagenes/
if (!is_dir("$base/imagenes")) mkdir("$base/imagenes", 0755, true);

// ── HTML FILES ───────────────────────────────────────────────────────
write_file("$base/index.html", "");
write_file("$base/huevo-proteinas.html", "");
