// ── VIDEO SYMLINK (from glvservicesexp.com) ────────────────────────────
$home = dirname(dirname(dirname($base)));
$vid_src = "$home/public_html/assets/videos/glv videos ovinos brasil/video corporativo glv services.mp4";
